                let _TEMP1 /* SDAI.LOGICAL */ = SDAI.TYPEOF( PDR.USED_REPRESENTATION, 
                  IS: eDIRECTION_SHAPE_REPRESENTATION.self )
                let _TEMP2 /* runtime? */ = /*runtime*/PDR.USED_REPRESENTATION
                let _TEMP3 /* runtime? */ = /*runtime*/_TEMP2?.NAME
                let _TEMP4 /* SDAI.LOGICAL */ = /*runtime*/_TEMP3 .==. SDAI.FORCE_OPTIONAL(SDAI.STRING(
                  "offset direction"))
                let _TEMP5 /* SDAI.LOGICAL */ = _TEMP1 && _TEMP4
                return _TEMP5
                // END QUERY BODY
              }
            let _TEMP3 /* SDAI.INTEGER? */ = SDAI.SIZEOF( _TEMP2 )
            let _TEMP4 /* SDAI.LOGICAL */ = _TEMP3 .==. SDAI.FORCE_OPTIONAL(SDAI.INTEGER(1))
            let _TEMP5 /* SDAI.LOGICAL */ =  !_TEMP4
            return _TEMP5
            // END QUERY BODY
          }
        let _TEMP6 /* SDAI.INTEGER? */ = SDAI.SIZEOF( _TEMP5 )
        let _TEMP7 /* SDAI.LOGICAL */ = _TEMP6 .==. SDAI.FORCE_OPTIONAL(SDAI.INTEGER(0))
        let _TEMP8 /* SDAI.LOGICAL */ = _TEMP2 || _TEMP7
        return _TEMP8
      }

      //EXPRESS IMPLICIT PARTIAL ENTITY CONSTRUCTOR
      /// initialize from explicit attribute values
      public init() {
        super.init(asAbstractSuperclass:())
      }

      //PARTIAL ENTITY COPY CONSTRUCTOR
      /// copy constructor
      public required convenience init(from original:SDAI.PartialEntity) {
        self.init( )
      }

      //p21 PARTIAL ENTITY CONSTRUCTOR
      /// initialize from ISO 10303-21 exchange structure parameters
      public required convenience init?(
        parameters: [P21Decode.ExchangeStructure.Parameter],
        exchangeStructure: P21Decode.ExchangeStructure
      ) {
        let numParams = 0
        guard parameters.count == numParams
        else { exchangeStructure.error = "number of p21 parameters(\(parameters.count)) are different from expected(\(numParams)) for partial entity(\(Self.entityName)) constructor"; return nil }

        self.init( )
      }
    }
  }
